  setMessageUnknownFields !ufs msg = msg { columnMetadataPageUnknownFields = ufs }

defaultColumnMetadata :: ColumnMetadata
defaultColumnMetadata = ColumnMetadata
  { columnMetadataEncoding = Nothing
  , columnMetadataPages = V.empty
  , columnMetadataBufferOffsets = VU.empty
  , columnMetadataBufferSizes = VU.empty
  , columnMetadataUnknownFields = []
  }

instance MessageEncode ColumnMetadata where
  buildMessage msg =
    (maybe mempty (\v -> let sz = messageSize v in archSubmessage 10 sz (buildMessage v)) msg.columnMetadataEncoding)
    <> V.foldl' (\acc v -> let sz = messageSize v in acc <> archSubmessage 18 sz (buildMessage v)) mempty msg.columnMetadataPages
    <> encodePackedWord64 3 msg.columnMetadataBufferOffsets
    <> encodePackedWord64 4 msg.columnMetadataBufferSizes
    <> encodeUnknownFields msg.columnMetadataUnknownFields

instance MessageSize ColumnMetadata where
  messageSize msg =
    (maybe 0 (\v -> archSubmessageSize (messageSize v)) msg.columnMetadataEncoding)
    + (V.foldl' (\acc v -> acc + archSubmessageSize (messageSize v)) 0 msg.columnMetadataPages)
    + (let pl = VU.foldl' (\a v -> a + varintSize v) 0 msg.columnMetadataBufferOffsets in if pl == 0 then 0 else tagSize 3 + varintSize (fromIntegral pl) + pl)
    + (let pl = VU.foldl' (\a v -> a + varintSize v) 0 msg.columnMetadataBufferSizes in if pl == 0 then 0 else tagSize 4 + varintSize (fromIntegral pl) + pl)
    + unknownFieldsSize msg.columnMetadataUnknownFields

instance MessageDecode ColumnMetadata where
  {-# INLINE messageDecoder #-}
  messageDecoder = loop Nothing V.empty VU.empty VU.empty []
    where
      loop acc_0 acc_1 acc_2 acc_3 acc_unknown_ = do
        mTag <- getTagOrU
        case mTag of
          UNothing -> pure (ColumnMetadata {columnMetadataEncoding = acc_0, columnMetadataPages = acc_1, columnMetadataBufferOffsets = acc_2, columnMetadataBufferSizes = acc_3, columnMetadataUnknownFields = reverse acc_unknown_})
          UJust (Tag fn wt) -> case fn of
            1 -> do
              v <- decodeFieldMessage
              loop (Just v) acc_1 acc_2 acc_3 acc_unknown_
            2 -> do
              v <- decodeFieldMessage
              loop acc_0 (acc_1 <> V.singleton v) acc_2 acc_3 acc_unknown_
            3 -> case wt of
              WireLengthDelimited -> do
                vs <- decodePackedVarint
                loop acc_0 acc_1 (acc_2 <> vs) acc_3 acc_unknown_
              _ -> do
                v <- decodeFieldVarint
                loop acc_0 acc_1 (acc_2 <> VU.singleton v) acc_3 acc_unknown_
            4 -> case wt of
              WireLengthDelimited -> do
                vs <- decodePackedVarint
                loop acc_0 acc_1 acc_2 (acc_3 <> vs) acc_unknown_
              _ -> do
                v <- decodeFieldVarint
                loop acc_0 acc_1 acc_2 (acc_3 <> VU.singleton v) acc_unknown_
            _ -> do
              uf <- captureUnknownField fn wt
              loop acc_0 acc_1 acc_2 acc_3 (uf : acc_unknown_)

