instance Aeson.ToJSON ColumnMetadata where
  toJSON msg = jsonObject
      [ "encoding" .=: msg.columnMetadataEncoding
      , "pages" .=: msg.columnMetadataPages
      , "bufferOffsets" .=: msg.columnMetadataBufferOffsets
      , "bufferSizes" .=: msg.columnMetadataBufferSizes
      ]

instance Aeson.FromJSON ColumnMetadata where
  parseJSON = Aeson.withObject "ColumnMetadata" $ \obj -> do
    fld_columnMetadataEncoding <- parseFieldMaybe obj "encoding"
    fld_columnMetadataPages <- parseFieldMaybe obj "pages"
    fld_columnMetadataBufferOffsets <- parseFieldMaybe obj "bufferOffsets"
    fld_columnMetadataBufferSizes <- parseFieldMaybe obj "bufferSizes"
    pure defaultColumnMetadata
      { columnMetadataEncoding = maybe (columnMetadataEncoding defaultColumnMetadata) id fld_columnMetadataEncoding
      , columnMetadataPages = maybe (columnMetadataPages defaultColumnMetadata) id fld_columnMetadataPages
      , columnMetadataBufferOffsets = maybe (columnMetadataBufferOffsets defaultColumnMetadata) id fld_columnMetadataBufferOffsets
      , columnMetadataBufferSizes = maybe (columnMetadataBufferSizes defaultColumnMetadata) id fld_columnMetadataBufferSizes
      }

instance Hashable ColumnMetadata where
  hashWithSalt salt msg = VU.foldl' hashWithSalt (VU.foldl' hashWithSalt (V.foldl' hashWithSalt (hashWithSalt (salt) msg.columnMetadataEncoding) msg.columnMetadataPages) msg.columnMetadataBufferOffsets) msg.columnMetadataBufferSizes

instance Proto.Extension.HasExtensions ColumnMetadata where
  messageUnknownFields = columnMetadataUnknownFields
  setMessageUnknownFields !ufs msg = msg { columnMetadataUnknownFields = ufs }

